/**
 * Telegram Notification Service
 * To use this, you need a Bot Token from @BotFather
 */

const BOT_TOKEN = '7774773824:AAHh7vO8YV4N7T3XF7U7U7U7U7U7U'; // Replace with your actual Bot Token

export const sendTelegramNotification = async (chatId: string, message: string) => {
  if (!chatId || !BOT_TOKEN || BOT_TOKEN.includes('REPLACE')) return;

  try {
    const url = `https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`;
    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        chat_id: chatId,
        text: message,
        parse_mode: 'HTML',
      }),
    });

    if (!response.ok) {
      console.error('Telegram notification failed', await response.text());
    }
  } catch (error) {
    console.error('Error sending Telegram notification:', error);
  }
};

