      default: return <Dashboard referrals={referrals} />;
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center font-cairo p-4">
        <div className="bg-white p-8 rounded-2xl shadow-lg w-full max-w-md">
