             <div className="w-16 h-16 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-4 shadow-lg"><Lock className="text-white" size={32} /></div>
             <h1 className="text-xl font-bold text-gray-800">نظام إحالة المتدربين</h1>
             <p className="text-gray-500 text-sm mt-2">يرجى تسجيل الدخول للمتابعة</p>
           </div>
           {isLoading ? <div className="flex flex-col items-center gap-4"><Loader2 className="animate-spin text-blue-600" size={32} /><p className="text-sm text-gray-500">جاري تحميل البيانات...</p></div> : (
             <form onSubmit={handleLogin} className="space-y-6">
               <div className="space-y-1">
                 <label className="text-sm font-bold text-gray-700 mr-1">المستخدم:</label>
                 <select 
                   value={loginUser} 
                   onChange={(e) => setLoginUser(e.target.value)} 
                   className="w-full p-3 border rounded-lg appearance-none bg-white focus:ring-2 focus:ring-blue-500 outline-none text-sm"
                 >
                   <option value="">اختر الاسم من القائمة...</option>
