               </div>
               {loginError && <div className="text-red-500 text-xs text-center font-bold bg-red-50 p-2 rounded-lg border border-red-100">{loginError}</div>}
               <button type="submit" className="w-full bg-blue-600 text-white py-3 rounded-lg font-bold hover:bg-blue-700 transition-colors shadow-md">دخول للنظام</button>
             </form>
           )}
