import React, { useMemo } from 'react';
import { Referral, ReferralStatus, CaseType } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';
import { Users, FileText, CheckCircle, AlertTriangle, TrendingUp, ArrowUpRight } from 'lucide-react';

interface DashboardProps {
  referrals: Referral[];
}

const COLORS = ['#2563eb', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4'];

const StatCard: React.FC<{ title: string; value: number; icon: React.ReactNode; color: string; subtitle: string }> = ({ title, value, icon, color, subtitle }) => (
  <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-shadow">
    <div className="flex justify-between items-start mb-4">
      <div className={`p-3 rounded-2xl ${color} bg-opacity-10 text-${color.split('-')[1]}-600`}>
        {icon}
      </div>
      <div className="flex items-center text-[10px] font-bold text-green-600 bg-green-50 px-2 py-1 rounded-full">
        <TrendingUp size={10} className="ml-1" /> نظامي
      </div>
    </div>
    <div>
      <h3 className="text-3xl font-black text-slate-800 mb-1">{value}</h3>
      <p className="text-slate-500 text-sm font-bold">{title}</p>
      <p className="text-[10px] text-slate-400 mt-2">{subtitle}</p>
    </div>
  </div>
);

const Dashboard: React.FC<DashboardProps> = ({ referrals }) => {
  const stats = useMemo(() => ({
    total: referrals.length,
    completed: referrals.filter(r => r.status === ReferralStatus.RESOLVED).length,
    pending: referrals.filter(r => r.status === ReferralStatus.PENDING_HOD || r.status === ReferralStatus.PENDING_COUNSELOR).length,
    critical: referrals.filter(r => r.status === ReferralStatus.TO_STUDENT_AFFAIRS).length,
  }), [referrals]);

  const chartData = useMemo(() => {
    const counts: any = {};
    referrals.forEach(r => r.caseTypes.forEach(t => counts[t] = (counts[t] || 0) + 1));
    return Object.entries(counts).map(([name, value]) => ({ name, value: value as number }));
  }, [referrals]);

  return (
    <div className="space-y-8 no-print">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="إجمالي الحالات" value={stats.total} icon={<FileText size={22} />} color="bg-blue-500" subtitle="حالات تم رصدها بالقسم" />
        <StatCard title="تمت المعالجة" value={stats.completed} icon={<CheckCircle size={22} />} color="bg-green-500" subtitle="إحالات منتهية بنجاح" />
        <StatCard title="قيد المتابعة" value={stats.pending} icon={<Users size={22} />} color="bg-amber-500" subtitle="بانتظار إجراء إداري" />
        <StatCard title="حالات حرجة" value={stats.critical} icon={<AlertTriangle size={22} />} color="bg-red-500" subtitle="محالة لشؤون المتدربين" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-lg font-black text-slate-800">تحليل أنواع المخالفات</h3>
            <button className="text-blue-600 text-xs font-bold flex items-center gap-1">تقرير مفصل <ArrowUpRight size={14}/></button>
          </div>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={chartData} cx="50%" cy="50%" innerRadius={60} outerRadius={100} paddingAngle={5} dataKey="value">
                  {chartData.map((_, index) => <Cell key={index} fill={COLORS[index % COLORS.length]} />)}
                </Pie>
                <Tooltip />
                <Legend layout="vertical" align="right" verticalAlign="middle" iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-black text-slate-800 mb-6">آخر النشاطات</h3>
          <div className="space-y-6">
            {referrals.slice(0, 5).map((r) => (
              <div key={r.id} className="flex gap-4 items-start group cursor-pointer">
                <div className={`w-2 h-10 rounded-full mt-1 ${r.status === ReferralStatus.RESOLVED ? 'bg-green-400' : 'bg-blue-400'}`}></div>
                <div className="flex-1">
                  <p className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors">{r.traineeName}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">{r.status}</p>
                </div>
                <p className="text-[10px] text-slate-400 mt-1">{new Date(r.date).toLocaleDateString('ar-EG')}</p>
              </div>
            ))}
            {referrals.length === 0 && <div className="text-center py-10 text-slate-300 text-sm">لا توجد سجلات حالياً</div>}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
