                  <p className="font-black text-slate-800 text-sm leading-none">{currentUser?.name}</p>
                  <p className="text-[10px] text-blue-600 font-black mt-1 uppercase tracking-tighter">{effectiveRole}</p>
                </div>
                <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-100 group-hover:scale-105 transition-transform">
