import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import MobileNav from './components/MobileNav';
import Dashboard from './pages/Dashboard';
import NewReferral from './pages/NewReferral';
import ReferralsList from './pages/ReferralsList';
import StaffManagement from './pages/StaffManagement';
import Profile from './pages/Profile';
import { Referral, Trainee, Staff, UserRole, ReferralStatus } from './types';
import { ShieldCheck, Lock, User, Bell, Loader2, LogIn, ChevronLeft, Database } from 'lucide-react';
import { db } from './services/firebase';
import { collection, onSnapshot, doc, setDoc, deleteDoc, updateDoc, query, orderBy } from 'firebase/firestore';

const INITIAL_STAFF: Staff[] = [
  { id: 'hod1', name: 'م. عبدالله الزهراني', username: 'م. عبدالله الزهراني', password: '0558882711', role: UserRole.HOD, specialization: 'محركات ومركبات' },
  { id: 'hod2', name: 'م. ياسر الشربي', username: 'م. ياسر الشربي', password: '0505709078', role: UserRole.HOD, specialization: 'تصنيع' },
  { id: 'counselor1', name: 'ماجد ابراهيم المرزوقي', username: 'ماجد ابراهيم المرزوقي', password: '1234', role: UserRole.TRAINER, specialization: 'توجيه وإرشاد', isCounselor: true },
];

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [loginUser, setLoginUser] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [loginError, setLoginError] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [activePage, setActivePage] = useState('dashboard');
  const [staff, setStaff] = useState<Staff[]>([]);
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [editingReferral, setEditingReferral] = useState<Referral | undefined>(undefined);

  useEffect(() => {
    const staffRef = collection(db, 'staff');
    const unsubscribe = onSnapshot(staffRef, async (snapshot) => {
      if (snapshot.empty && navigator.onLine) {
        for (const s of INITIAL_STAFF) { await setDoc(doc(db, 'staff', s.id), s); }
      } else {
        const staffData = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Staff));
        staffData.sort((a, b) => a.name.localeCompare(b.name, 'ar'));
        setStaff(staffData);
        setIsLoading(false);
      }
    }, (err) => { 
      console.error("Firebase Connection Error:", err); 
      setIsLoading(false); 
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const q = query(collection(db, 'referrals'), orderBy('date', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      setReferrals(snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Referral)));
    });
    return () => unsubscribe();
  }, []);

  const pendingCount = useMemo(() => {
    if (!currentUser) return 0;
    return referrals.filter(r => {
      if (currentUser.role === UserRole.HOD) {
        return (r.status === ReferralStatus.PENDING_HOD || r.status === ReferralStatus.RETURNED_TO_HOD) && r.specialization === currentUser.specialization;
      }
      if (currentUser.isCounselor) return r.status === ReferralStatus.PENDING_COUNSELOR;
      return false;
    }).length;
  }, [referrals, currentUser]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = staff.find(s => s.username === loginUser && s.password === loginPass);
    if (user) {
      setCurrentUser(user);
      setIsAuthenticated(true);
      setActivePage(user.role === UserRole.HOD || user.isCounselor ? 'dashboard' : 'new-referral');
    } else {
      setLoginError('بيانات الدخول غير صحيحة');
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;
    const commonProps = { currentUser, staff, referrals };
    switch (activePage) {
      case 'dashboard': return <Dashboard referrals={referrals} />;
      case 'new-referral': 
        return <NewReferral {...commonProps} trainees={[]} 
          onSubmit={async (r) => { 
            await setDoc(doc(db, 'referrals', r.id), r); 
            setEditingReferral(undefined);
            setActivePage('referrals'); 
          }} 
          onCancel={() => {
            setEditingReferral(undefined);
            setActivePage('dashboard');
          }} 
          initialData={editingReferral} 
        />;
      case 'referrals': 
        return <ReferralsList referrals={referrals} currentUser={currentUser} 
          onEdit={(r) => { setEditingReferral(r); setActivePage('new-referral'); }} 
          onDelete={async (id) => await deleteDoc(doc(db, 'referrals', id))} />;
      case 'staff': return <StaffManagement staff={staff} setStaff={() => {}} currentUserSpecialization={currentUser.specialization} />;
      case 'profile': return <Profile currentUser={currentUser} updateUserPassword={async (p) => await updateDoc(doc(db, 'staff', currentUser.id), {password: p})} onUpdateTelegram={async (id) => await updateDoc(doc(db, 'staff', currentUser.id), {telegramChatId: id})} />;
      default: return <Dashboard referrals={referrals} />;
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-premium flex items-center justify-center p-6 font-cairo">
        <div className="bg-white/95 backdrop-blur-xl p-10 rounded-[2.5rem] shadow-2xl w-full max-w-md border border-white/20 fade-in">
          <div className="text-center mb-10">
            <div className="w-24 h-24 bg-blue-600/10 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-inner">
              <ShieldCheck className="text-blue-600" size={52} />
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">نظام الإحالة الرقمي</h1>
            <p className="text-slate-500 mt-2 font-bold">قسم التقنية الميكانيكية</p>
          </div>

          {isLoading ? (
            <div className="flex flex-col items-center py-10">
              <Loader2 className="animate-spin text-blue-600 mb-4" size={40} />
              <p className="text-slate-400 font-bold">جاري المزامنة مع Firestore...</p>
            </div>
          ) : (
            <form onSubmit={handleLogin} className="space-y-6">
              <div className="space-y-2">
                <label className="text-sm font-black text-slate-700 mr-2 flex items-center gap-2">
                  <User size={16} className="text-blue-500" /> اختر الهوية الوظيفية
                </label>
                <div className="relative group">
                  <select 
                    value={loginUser} 
                    onChange={(e) => setLoginUser(e.target.value)} 
                    className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl appearance-none focus:border-blue-500 focus:bg-white outline-none text-sm transition-all font-bold text-slate-800"
                    required
                  >
                    <option value="">من القائمة...</option>
                    {staff.map(s => (
                      <option key={s.id} value={s.username}>
                        {s.name} - [{s.isCounselor ? 'مرشد تدريبي' : s.role}]
                      </option>
                    ))}
                  </select>
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                    <ChevronLeft size={20} />
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-black text-slate-700 mr-2 flex items-center gap-2">
                  <Lock size={16} className="text-blue-500" /> رمز المرور
                </label>
                <input 
                  type="password" 
                  value={loginPass} 
                  onChange={(e) => setLoginPass(e.target.value)} 
                  className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:bg-white outline-none transition-all font-mono tracking-widest text-center text-lg"
                  placeholder="••••"
                  required
                />
              </div>

              {loginError && <div className="p-4 bg-red-50 text-red-600 text-xs font-black rounded-2xl text-center border border-red-100">{loginError}</div>}

              <button type="submit" className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 flex items-center justify-center gap-3 group active:scale-[0.98]">
                <LogIn size={20} className="group-hover:-translate-x-1 transition-transform" />
                الدخول للنظام
              </button>
            </form>
          )}
          <div className="mt-12 text-center text-[10px] text-slate-400 font-black uppercase tracking-widest">
            الكلية التقنية بالطائف © 2025
          </div>
        </div>
      </div>
    );
  }

  const effectiveRole = currentUser?.isCounselor ? UserRole.COUNSELOR : (currentUser?.role || UserRole.TRAINER);

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] font-cairo overflow-hidden">
      <Sidebar 
        activePage={activePage} 
        setActivePage={(p) => { 
          if(p !== 'new-referral') setEditingReferral(undefined);
          setActivePage(p); 
        }} 
        currentUserRole={effectiveRole} 
        onLogout={() => setIsAuthenticated(false)} 
        notificationCount={pendingCount} 
      />
      <main className="flex-1 p-4 md:p-10 overflow-y-auto pb-28 relative">
        <header className="mb-10 flex justify-between items-center no-print">
           <div className="flex items-center gap-4">
             <div>
               <h1 className="text-2xl font-black text-slate-900 tracking-tight">
                 {activePage === 'dashboard' ? 'لوحة المعلومات' : activePage === 'new-referral' ? 'إحالة جديدة' : activePage === 'referrals' ? 'سجل الحالات' : 'الإعدادات'}
               </h1>
               <p className="text-slate-400 text-xs font-bold mt-1">المستخدم الحالي: {currentUser?.name}</p>
             </div>
           </div>

           <div className="flex items-center gap-4">
              <button className="relative p-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-600 hover:text-blue-600 transition-all group">
                <Bell size={22} className="group-hover:rotate-12 transition-transform" />
                {pendingCount > 0 && <span className="absolute top-2.5 right-2.5 bg-red-500 w-2.5 h-2.5 rounded-full border-2 border-white ring-2 ring-red-100"></span>}
              </button>

              <div 
                className="flex items-center gap-3 bg-white p-2 pr-4 rounded-2xl shadow-sm border border-slate-100 cursor-pointer hover:border-blue-200 transition-all" 
                onClick={() => setActivePage('profile')}
              >
                <div className="text-left hidden md:block">
                  <p className="font-black text-slate-800 text-sm leading-none">{currentUser?.name}</p>
                  <p className="text-[10px] text-blue-600 font-black mt-1 uppercase tracking-tighter">{effectiveRole}</p>
                </div>
                <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white">
                  <User size={22} />
                </div>
              </div>
           </div>
        </header>

        <div className="fade-in">
          {renderContent()}
        </div>
      </main>
      <MobileNav activePage={activePage} setActivePage={setActivePage} currentUserRole={effectiveRole} notificationCount={pendingCount} onLogout={() => setIsAuthenticated(false)} />
    </div>
  );
};

export default App;

