const escapeHTML = (text: string): string => {
  if (!text) return '';
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
};

export const sendTelegramNotification = async (chatId: string, message: string) => {
  if (!chatId || !BOT_TOKEN || BOT_TOKEN.includes('REPLACE')) return;

  const url = `https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`;

  const sendRequest = async (useHtml: boolean) => {
    return fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: chatId,
        text: message,
        parse_mode: useHtml ? 'HTML' : undefined,
      }),
    });
  };

  try {
    let response = await sendRequest(true);

    // If HTML parsing fails (common with special chars), fallback to plain text
    if (!response.ok) {
      const errorData = await response.json();
      console.warn('Telegram HTML send failed, trying plain text...', errorData);

      // Clean the message for plain text if it failed due to entities
      const plainMessage = message.replace(/<[^>]*>/g, ''); 
