import { GoogleGenAI } from "@google/genai";
import { CaseType, Repetition } from "../types";

/**
 * Analyzes case details using Gemini AI based on the provided parameters.
 * Follows world-class engineering standards and GenAI SDK guidelines.
 */
export const analyzeCaseWithGemini = async (
  caseDetails: string,
  caseTypes: CaseType[],
  repetition: Repetition,
  previousActions: string
): Promise<string> => {
  try {
    // Fix: Obtain API key exclusively from process.env.API_KEY and use it directly in the constructor
    // Create the client right before the call to ensure it uses the current valid key
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Fix: Use systemInstruction in the config to define the model's persona and task constraints
    const systemInstruction = "بصفتك مستشاراً تربوياً وتدريبياً خبيراً، قم بتحليل حالة المتدرب التالية واقترح حلولاً عملية ومهنية للمرشد التدريبي. قدم توصية موجزة ومهنية (لا تتجاوز 100 كلمة) تتضمن خطوات إجرائية محددة لحل المشكلة وتعديل السلوك أو تحسين المستوى التدريبي.";

    const prompt = `
      بيانات الحالة:
      - نوع المشكلة: ${caseTypes.join(', ')}
      - تكرار المشكلة: ${repetition}
      - تفاصيل الحالة: ${caseDetails}
      - الإجراءات السابقة التي اتخذها المدرب: ${previousActions}

      المطلوب:
      بناءً على البيانات أعلاه، قدم التوصية المهنية والخطوات الإجرائية المطلوبة.
    `;

    // Fix: Call generateContent with the model name directly in the request object.
    // 'gemini-3-pro-preview' is selected for complex reasoning and analysis tasks.
    // Added thinkingConfig with a budget to allow the model to reason more deeply.
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });

    // Fix: Extract generated text via the .text property (not a method)
    return response.text || "لم يتم إنشاء تحليل.";
  } catch (error) {
    console.error("Error calling Gemini API:", error);
    return "حدث خطأ أثناء تحليل الحالة بواسطة الذكاء الاصطناعي.";
  }
};

