import React, { useState, useEffect } from 'react';
import { Staff } from '../types';
import { Lock, Save, Send, Loader2, CheckCircle, AlertCircle, BellRing, Smartphone } from 'lucide-react';

interface ProfileProps {
  currentUser: Staff;
  updateUserPassword: (password: string) => Promise<void>;
  onUpdateTelegram: (chatId: string) => Promise<void>;
}

const Profile: React.FC<ProfileProps> = ({ currentUser, updateUserPassword, onUpdateTelegram }) => {
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [telegramChatId, setTelegramChatId] = useState(currentUser.telegramChatId || '');

  const [isSavingPass, setIsSavingPass] = useState(false);
  const [isSavingTelegram, setIsSavingTelegram] = useState(false);
  const [passFeedback, setPassFeedback] = useState<{ type: 'success' | 'error', msg: string } | null>(null);
  const [teleFeedback, setTeleFeedback] = useState<{ type: 'success' | 'error', msg: string } | null>(null);

  // حالة إشعارات المتصفح
  const [browserNotificationStatus, setBrowserNotificationStatus] = useState<string>('default');

  useEffect(() => {
    if ("Notification" in window) {
      setBrowserNotificationStatus(Notification.permission);
    }
  }, []);

  const requestBrowserPermission = async () => {
    if (!("Notification" in window)) {
      alert("هذا المتصفح لا يدعم الإشعارات.");
      return;
    }
    const permission = await Notification.requestPermission();
    setBrowserNotificationStatus(permission);
    if (permission === 'granted') {
      new Notification("تم التفعيل", { body: "ستصلك إشعارات النظام على هذا الجهاز بنجاح." });
    }
  };

  const testBrowserNotification = () => {
    if (Notification.permission === 'granted') {
      new Notification("اختبار النظام", { 
        body: "هذا مثال لشكل الإشعار عند وصول إحالة جديدة.",
        icon: 'https://cdn-icons-png.flaticon.com/512/3119/3119338.png'
      });
    } else {
      alert("يرجى تفعيل الصلاحية أولاً.");
    }
  };

  const handleSubmitPass = async (e: React.FormEvent) => {
    e.preventDefault();
    setPassFeedback(null);
    if (newPassword.length < 4) {
      setPassFeedback({ type: 'error', msg: 'كلمة المرور يجب أن تكون 4 خانات على الأقل' });
      return;
    }
    if (newPassword !== confirmPassword) {
      setPassFeedback({ type: 'error', msg: 'كلمتا المرور غير متطابقتين' });
      return;
    }
    const confirmed = window.confirm('هل أنت متأكد من تغيير كلمة المرور؟');
    if (!confirmed) return;
    setIsSavingPass(true);
    try {
      await updateUserPassword(newPassword);
      setPassFeedback({ type: 'success', msg: 'تم تغيير كلمة المرور بنجاح' });
      setNewPassword('');
      setConfirmPassword('');
    } catch (error) {
      setPassFeedback({ type: 'error', msg: 'حدث خطأ أثناء التحديث' });
    } finally {
      setIsSavingPass(false);
    }
  };

  const handleUpdateTelegram = async () => {
    setTeleFeedback(null);
    setIsSavingTelegram(true);
    try {
      await onUpdateTelegram(telegramChatId);
      setTeleFeedback({ type: 'success', msg: 'تم تحديث معرف التيليجرام بنجاح' });
    } catch (error) {
      setTeleFeedback({ type: 'error', msg: 'حدث خطأ أثناء الحفظ' });
    } finally {
      setIsSavingTelegram(false);
    }
  };

  return (
    <div className="max-w-md mx-auto mt-10 space-y-6 pb-20 px-4">
      {/* قسم إشعارات المتصفح الجديد */}
      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
        <div className="text-center mb-6">
          <div className={`w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-4 shadow-inner ${browserNotificationStatus === 'granted' ? 'bg-green-100 text-green-600' : 'bg-orange-100 text-orange-600'}`}>
            <BellRing size={32} />
          </div>
          <h2 className="text-xl font-black text-slate-900">إشعارات المتصفح</h2>
          <p className="text-sm text-slate-400 font-bold mt-1">تنبيهات فورية على الجوال والكومبيوتر</p>
        </div>

        <div className="space-y-4">
           {browserNotificationStatus === 'granted' ? (
             <div className="p-4 bg-green-50 border border-green-100 rounded-2xl flex items-center gap-3">
               <CheckCircle className="text-green-500" size={20} />
               <span className="text-xs font-black text-green-800">الإشعارات مفعلة على هذا الجهاز</span>
             </div>
           ) : browserNotificationStatus === 'denied' ? (
             <div className="p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-3">
               <AlertCircle className="text-red-500" size={20} />
               <span className="text-xs font-black text-red-800">الإشعارات محظورة. يرجى تفعيلها من إعدادات المتصفح.</span>
             </div>
           ) : (
             <button
                onClick={requestBrowserPermission}
                className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg shadow-blue-200 hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-2"
             >
                <Smartphone size={18} /> تفعيل الإشعارات الآن
             </button>
           )}

           {browserNotificationStatus === 'granted' && (
             <button
               onClick={testBrowserNotification}
               className="w-full py-3 border-2 border-slate-100 text-slate-600 rounded-2xl font-black text-xs hover:bg-slate-50 transition-all"
             >
               إرسال إشعار تجريبي للجهاز
             </button>
           )}
        </div>
      </div>

      {/* قسم التيليجرام */}
      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
        <div className="text-center mb-6">
          <div className="w-20 h-20 bg-blue-50 rounded-3xl flex items-center justify-center mx-auto mb-4 text-blue-500 shadow-inner">
            <Send size={32} />
          </div>
          <h2 className="text-xl font-black text-slate-900">إشعارات التيليجرام</h2>
        </div>
        <div className="space-y-4">
          <div className="space-y-1.5">
            <label className="block text-xs font-black text-slate-500 pr-1 uppercase tracking-wider">Telegram Chat ID</label>
            <input
              type="text"
              value={telegramChatId}
              onChange={(e) => setTelegramChatId(e.target.value)}
              className="w-full p-4 bg-slate-50 border-2 border-transparent rounded-2xl focus:border-blue-500 focus:bg-white outline-none transition-all font-mono text-center text-lg font-bold"
              placeholder="مثال: 12345678"
            />
          </div>
          <button
            onClick={handleUpdateTelegram}
            disabled={isSavingTelegram}
            className={`w-full py-4 rounded-2xl transition-all font-black flex items-center justify-center gap-2 shadow-lg ${isSavingTelegram ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200'}`}
          >
            {isSavingTelegram ? <Loader2 className="animate-spin" size={20} /> : <Save size={18} />}
            {isSavingTelegram ? 'جاري الحفظ...' : 'حفظ معرف التيليجرام'}
          </button>
          {teleFeedback && (
            <div className={`flex items-center gap-2 p-3 rounded-xl text-xs font-bold ${teleFeedback.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
              {teleFeedback.type === 'success' ? <CheckCircle size={14} /> : <AlertCircle size={14} />}
              {teleFeedback.msg}
            </div>
          )}
        </div>
      </div>

      {/* قسم كلمة المرور */}
      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
        <div className="flex items-center gap-3 mb-6">
          <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-900">
            <Lock size={20}/>
          </div>
          <h3 className="text-lg font-black text-slate-900">أمان الحساب</h3>
        </div>
        <form onSubmit={handleSubmitPass} className="space-y-4">
          <div className="space-y-1.5">
            <label className="block text-xs font-black text-slate-500 pr-1 uppercase">كلمة المرور الجديدة</label>
            <input type="password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} className="w-full p-4 bg-slate-50 border-2 border-transparent rounded-2xl focus:border-slate-900 focus:bg-white outline-none transition-all font-mono tracking-widest text-center" placeholder="••••" />
          </div>
          <div className="space-y-1.5">
            <label className="block text-xs font-black text-slate-500 pr-1 uppercase">تأكيد كلمة المرور</label>
            <input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} className="w-full p-4 bg-slate-50 border-2 border-transparent rounded-2xl focus:border-slate-900 focus:bg-white outline-none transition-all font-mono tracking-widest text-center" placeholder="••••" />
          </div>
          <button type="submit" disabled={isSavingPass} className={`w-full py-4 rounded-2xl transition-all font-black flex items-center justify-center gap-2 shadow-xl ${isSavingPass ? 'bg-slate-100 text-slate-400' : 'bg-slate-900 text-white hover:bg-black'}`}>
            {isSavingPass ? <Loader2 className="animate-spin" size={20} /> : <Save size={18} />}
            تحديث البيانات
          </button>
          {passFeedback && (
            <div className={`flex items-center gap-2 p-3 rounded-xl text-xs font-bold ${passFeedback.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
              {passFeedback.type === 'success' ? <CheckCircle size={14} /> : <AlertCircle size={14} />}
              {passFeedback.msg}
            </div>
          )}
        </form>
      </div>
    </div>
  );
};

export default Profile;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import MobileNav from './components/MobileNav';
import Dashboard from './pages/Dashboard';
import NewReferral from './pages/NewReferral';
import ReferralsList from './pages/ReferralsList';
import StaffManagement from './pages/StaffManagement';
import DataImport from './pages/DataImport';
import Profile from './pages/Profile';
import { Referral, Staff, UserRole, ReferralStatus, Trainee } from './types';
import { ShieldCheck, Lock, User, Bell, Loader2, LogIn, ChevronLeft, Code2 } from 'lucide-react';
import { db } from './services/firebase';
import { collection, onSnapshot, doc, setDoc, deleteDoc, updateDoc, query, orderBy } from 'firebase/firestore';
import { sendTelegramNotification, formatReferralMessage } from './services/telegramService';

/**
 * وظيفة أمنية لتوليد بصمة رقمية مشفرة لكلمة المرور (SHA-256)
 */
export const hashPassword = async (password: string): Promise<string> => {
  const encoder = new TextEncoder();
  const data = encoder.encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

// بصمة مشفرة لكلمة المرور الافتراضية "123"
const INITIAL_HASH = "a665a45920422f9d417e4867efdc4fb8a04a1f3fff1fa07e998e86f7f7a27ae3";

const INITIAL_STAFF: Staff[] = [
  { id: 'hod1', name: 'م. عبدالله الزهراني', username: 'م. عبدالله Zahrani', password: INITIAL_HASH, role: UserRole.HOD, specialization: 'محركات ومركبات' },
  { id: 'hod2', name: 'م. ياسر الشربي', username: 'م. ياسر الشربي', password: INITIAL_HASH, role: UserRole.HOD, specialization: 'تصنيع' },
  { id: 'counselor1', name: 'ماجد ابراهيم المرزوقي', username: 'ماجد ابراهيم المرزوقي', password: INITIAL_HASH, role: UserRole.TRAINER, specialization: 'توجيه وإرشاد', isCounselor: true },
];

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [loginUser, setLoginUser] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [loginError, setLoginError] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [activePage, setActivePage] = useState('dashboard');
  const [staff, setStaff] = useState<Staff[]>([]);
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [trainees, setTrainees] = useState<Trainee[]>([]);
  const [editingReferral, setEditingReferral] = useState<Referral | undefined>(undefined);

  // طلب صلاحية الإشعارات عند التشغيل
  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission();
    }
  }, []);

  useEffect(() => {
    let unsubscribe = () => {};
    try {
      const staffRef = collection(db, 'staff');
      unsubscribe = onSnapshot(staffRef, async (snapshot) => {
        if (snapshot.empty && navigator.onLine) {
          for (const s of INITIAL_STAFF) { 
            await setDoc(doc(db, 'staff', s.id), s); 
          }
        } else {
          const staffData = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Staff));
          staffData.sort((a, b) => a.name.localeCompare(b.name, 'ar'));
          setStaff(staffData);
          setIsLoading(false);
        }
      }, (err) => { 
        console.error("Firestore Error (Staff):", err);
        if (staff.length === 0) setStaff(INITIAL_STAFF);
        setIsLoading(false);
      });
    } catch (e) {
      console.error("Firestore Setup Error (Staff):", e);
      setStaff(INITIAL_STAFF);
      setIsLoading(false);
    }
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    let unsubscribe = () => {};
    try {
      const q = query(collection(db, 'referrals'), orderBy('date', 'desc'));
      unsubscribe = onSnapshot(q, (snapshot) => {
        setReferrals(snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Referral)));
      }, (err) => console.warn("Firestore Error (Referrals):", err));
    } catch (e) {
      console.error("Firestore Setup Error (Referrals):", e);
    }
    return () => unsubscribe();
  }, []);

  const pendingCount = useMemo(() => {
    if (!currentUser) return 0;
    return referrals.filter(r => {
      if (currentUser.role === UserRole.HOD) {
        return (r.status === ReferralStatus.PENDING_HOD || r.status === ReferralStatus.RETURNED_TO_HOD) && r.specialization === currentUser.specialization;
      }
      if (currentUser.isCounselor) return r.status === ReferralStatus.PENDING_COUNSELOR;
      return false;
    }).length;
  }, [referrals, currentUser]);

  // Fix: Defined effectiveRole to resolve reference errors in Sidebar and MobileNav components.
  // This calculates the visual role based on whether a trainer is also a counselor.
  const effectiveRole = useMemo(() => {
    if (!currentUser) return UserRole.TRAINER;
    if (currentUser.role === UserRole.HOD) return UserRole.HOD;
    if (currentUser.isCounselor) return UserRole.COUNSELOR;
    return currentUser.role;
  }, [currentUser]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');

    const inputHash = await hashPassword(loginPass);
    const user = staff.find(s => s.username === loginUser);

    if (!user) {
      setLoginError('بيانات الدخول غير صحيحة');
      return;
    }

    if (user.password === inputHash || user.password === loginPass) {
      if (user.password === loginPass) {
        await updateDoc(doc(db, 'staff', user.id), { password: inputHash });
      }
      setCurrentUser(user);
      setIsAuthenticated(true);
      setActivePage(user.role === UserRole.HOD || user.isCounselor ? 'dashboard' : 'new-referral');

      // التأكد من طلب الإذن عند الدخول
      if ("Notification" in window) {
        Notification.requestPermission();
      }
      return;
    }

    setLoginError('بيانات الدخول غير صحيحة');
  };

  const triggerNotifications = async (r: Referral) => {
    if (!currentUser || !staff.length) return;
    const allowedStatuses = [ReferralStatus.PENDING_HOD, ReferralStatus.PENDING_COUNSELOR];
    if (!allowedStatuses.includes(r.status)) return;

    const lastEvent = r.timeline[r.timeline.length - 1];
    const msg = formatReferralMessage(lastEvent.action, r.traineeName, r.status, currentUser.name, lastEvent.comment);

    // إرسال إشعار المتصفح المحلى
    if ("Notification" in window && Notification.permission === "granted") {
      new Notification("تنبيه نظام الإحالة", {
        body: `${lastEvent.action}: للمتدرب ${r.traineeName}`,
        icon: 'https://cdn-icons-png.flaticon.com/512/3119/3119338.png',
        dir: 'rtl'
      });
    }

    let recipientsToNotify: Staff[] = [];
    const originalTrainer = staff.find(s => s.id === r.trainerId);
    if (originalTrainer) recipientsToNotify.push(originalTrainer);
    const HODs = staff.filter(s => s.role === UserRole.HOD && s.specialization === r.specialization);
    recipientsToNotify.push(...HODs);
    const counselors = staff.filter(s => s.isCounselor);
    recipientsToNotify.push(...counselors);

    const uniqueRecipients = Array.from(new Set(recipientsToNotify.map(s => s.id)))
      .map(id => staff.find(s => s.id === id))
      .filter((s): s is Staff => !!s && !!s.telegramChatId && s.id !== currentUser.id);

    try {
      await Promise.all(uniqueRecipients.map(recipient => 
        sendTelegramNotification(recipient.telegramChatId!, msg)
      ));
    } catch (error) {
      console.error('Fast Notification Error:', error);
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;
    const commonProps = { currentUser, staff, referrals };
    switch (activePage) {
      case 'dashboard': return <Dashboard referrals={referrals} />;
      case 'new-referral': 
        return <NewReferral {...commonProps} trainees={trainees} 
          onSubmit={async (r) => { 
            await setDoc(doc(db, 'referrals', r.id), r); 
            triggerNotifications(r).catch(e => console.error("Notification BG Error:", e));
            setEditingReferral(undefined);
            setActivePage('referrals'); 
          }} 
          onCancel={() => {
            setEditingReferral(undefined);
            setActivePage('dashboard');
          }} 
          initialData={editingReferral} 
        />;
      case 'referrals': 
        return <ReferralsList referrals={referrals} currentUser={currentUser} 
          onEdit={(r) => { setEditingReferral(r); setActivePage('new-referral'); }} 
          onDelete={async (id) => await deleteDoc(doc(db, 'referrals', id))} />;
      case 'staff': return <StaffManagement staff={staff} setStaff={() => {}} currentUserSpecialization={currentUser.specialization} />;
      case 'import': return <DataImport trainees={trainees} setTrainees={setTrainees} staff={staff} setStaff={() => {}} />;
      case 'profile': return <Profile currentUser={currentUser} 
        updateUserPassword={async (p) => {
          const hashed = await hashPassword(p);
          await updateDoc(doc(db, 'staff', currentUser.id), { password: hashed });
        }} 
        onUpdateTelegram={async (id) => await updateDoc(doc(db, 'staff', currentUser.id), { telegramChatId: id })} />;
      default: return <Dashboard referrals={referrals} />;
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen login-bg flex flex-col items-center justify-center p-6 font-cairo">
        <div className="glass-card p-10 rounded-[2.5rem] w-full max-w-md fade-in-up">
          <div className="text-center mb-10">
            <div className="w-24 h-24 bg-blue-600/10 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-inner ring-4 ring-white/50">
              <ShieldCheck className="text-blue-500" size={52} />
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">نظام الإحالة الرقمي</h1>
            <p className="text-slate-500 mt-2 font-bold text-sm">الكلية التقنية بالطائف - التقنية الميكانيكية</p>
          </div>

          {isLoading ? (
            <div className="flex flex-col items-center py-10">
              <Loader2 className="animate-spin text-blue-600 mb-4" size={40} />
              <p className="text-slate-400 font-bold text-center">جاري الاتصال بقاعدة البيانات السحابية...</p>
            </div>
          ) : (
            <form onSubmit={handleLogin} className="space-y-6">
              <div className="space-y-2">
                <label className="text-sm font-black text-slate-700 flex items-center gap-2 pr-1">
                  <User size={16} className="text-blue-500" /> اختر هويتك الوظيفية
                </label>
                <div className="relative">
                  <select 
                    value={loginUser} 
                    onChange={(e) => setLoginUser(e.target.value)} 
                    className="w-full p-4 bg-white/50 border-2 border-slate-100 rounded-2xl appearance-none focus:border-blue-500 focus:bg-white outline-none text-sm transition-all font-bold text-slate-800 shadow-sm"
                    required
                  >
                    <option value="">اختر اسمك...</option>
                    {staff.map(s => (
                      <option key={s.id} value={s.username}>
                        {s.name} ({s.isCounselor ? 'مرشد' : s.role})
                      </option>
                    ))}
                  </select>
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                    <ChevronLeft size={20} />
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-black text-slate-700 flex items-center gap-2 pr-1">
                  <Lock size={16} className="text-blue-500" /> كلمة المرور
                </label>
                <input 
                  type="password" 
                  value={loginPass} 
                  onChange={(e) => setLoginPass(e.target.value)} 
                  className="w-full p-4 bg-white/50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:bg-white outline-none transition-all font-mono tracking-widest text-center text-lg shadow-sm"
                  placeholder="••••"
                  required
                />
              </div>

              {loginError && <div className="p-4 bg-red-50 text-red-600 text-xs font-black rounded-2xl text-center border border-red-100 animate-pulse">{loginError}</div>}

              <button type="submit" className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 flex items-center justify-center gap-3 group active:scale-[0.98]">
                <LogIn size={22} className="group-hover:-translate-x-1 transition-transform" />
                دخول آمن للنظام
              </button>
            </form>
          )}
          <div className="mt-12 text-center flex flex-col items-center gap-2">
             <div className="flex items-center gap-2 text-slate-400 bg-slate-100 px-4 py-2 rounded-full border border-slate-200 shadow-inner">
                <Code2 size={14} />
                <span className="text-[11px] font-black uppercase tracking-widest">تطوير: م. عبدالله الزهراني</span>
             </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] font-cairo overflow-hidden">
      <Sidebar 
        activePage={activePage} 
        setActivePage={(p) => { 
          if(p !== 'new-referral') setEditingReferral(undefined);
          setActivePage(p); 
        }} 
        currentUserRole={effectiveRole} 
        onLogout={() => setIsAuthenticated(false)} 
        notificationCount={pendingCount} 
      />
      <main className="flex-1 p-4 md:p-10 overflow-y-auto pb-28 relative">
        <header className="mb-10 flex justify-between items-center no-print">
