const BOT_TOKEN = '8589128782:AAEvXaKJxFipipYhbX8TJ9u9rBzEN_FHr4o';

/**
 * Escapes HTML special characters to prevent Telegram API errors
 */
const escapeHTML = (text: string): string => {
  if (!text) return '';
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
};

export const sendTelegramNotification = async (chatId: string, message: string) => {
  if (!chatId || !BOT_TOKEN || BOT_TOKEN.includes('REPLACE')) {
    console.warn('Telegram Configuration Missing: Chat ID or Token');
    return;
  }

  const url = `https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`;

  const sendRequest = async (useHtml: boolean) => {
    return fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: chatId,
        text: message,
        parse_mode: useHtml ? 'HTML' : undefined,
      }),
    });
  };

  try {
    let response = await sendRequest(true);
    let result = await response.json();

    if (!response.ok) {
      console.error('Telegram Error Response:', result);

      // Fallback to plain text if HTML error
      if (result.description?.includes('can\'t parse entities')) {
        const plainMessage = message.replace(/<[^>]*>/g, ''); 
        response = await fetch(url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            chat_id: chatId,
            text: plainMessage,
          }),
        });
        result = await response.json();
      }
    }

    if (!response.ok) {
      throw new Error(result.description || 'Unknown Telegram Error');
    }

    return result;
  } catch (error) {
    console.error('Network error during Telegram notification send:', error);
    throw error;
  }
};

