        <div className="fade-in-up">{renderContent()}</div>
      </main>
      <MobileNav activePage={activePage} setActivePage={setActivePage} currentUserRole={effectiveRole} notificationCount={pendingCount} onLogout={() => setIsAuthenticated(false)} />
    </div>
  );
};

